"""Needsyml SVG BDD directive — renders inline SVG using sphinx-need-svg.

We build a pre-baked Jinja template (root, children-from-filter, layout)
and hand it off to sphinx-need-svg's ``Needsvg`` placeholder node so that
rendering happens at ``doctree-resolved`` time. Doing the render in our
own ``run()`` would call ``SphinxNeedsData.get_needs_view()`` mid-parse,
which freezes the needs registry and breaks every later directive.
"""

from typing import Any

from docutils import nodes
from docutils.parsers.rst import directives
from sphinx.application import Sphinx
from sphinx.util.docutils import SphinxDirective


_SVG_TEMPLATE = """\
{% set root_id = "__ROOT_ID__" %}
{% set children = filter("__FILTER_EXPR__") | list %}
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 720 260" width="100%">
  {% set root = needs.get(root_id) %}
  {% if root %}
  <g transform="translate(300, 20)">{{ flow(root_id) }}</g>
  {% set count = children | length %}
  {% if count > 0 %}
  {% set step = (720 // (count + 1)) %}
  {% for child in children %}
  {% set cx = step * loop.index %}
  <line x1="360" y1="60" x2="{{ cx }}" y2="180"
        stroke="#336699" stroke-width="1.5"/>
  <polygon points="358,55 366,55 362,65" fill="#336699"/>
  <g transform="translate({{ cx - 60 }}, 180)">{{ flow(child.id) }}</g>
  {% endfor %}
  {% else %}
  <text x="360" y="150" text-anchor="middle"
        font-family="sans-serif" font-size="12" fill="#999">
    No children matching filter
  </text>
  {% endif %}
  {% else %}
  <text x="360" y="130" text-anchor="middle"
        font-family="sans-serif" font-size="12" fill="red">
    Unknown root need: {{ root_id }}
  </text>
  {% endif %}
</svg>
"""


class NeedsymlBddSvgDirective(SphinxDirective):
    """Generate a Block Definition Diagram as inline SVG.

    Defers to sphinx-need-svg's ``Needsvg`` placeholder so rendering
    happens after all needs have been collected.
    """

    required_arguments = 1
    optional_arguments = 0
    final_argument_whitespace = True
    option_spec = {
        "depth": directives.unchanged,
        "filter": directives.unchanged,
        "align": directives.unchanged,
        "width": directives.unchanged,
    }

    def run(self) -> list[Any]:
        from sphinx_need_svg.directives.needsvg import Needsvg

        root_id = self.arguments[0]
        align = self.options.get("align", "center")
        width = self.options.get("width", "100%")
        filter_expr = self.options.get(
            "filter", f"type == 'PartDef' and owned_by == '{root_id}'"
        )

        content = _SVG_TEMPLATE.replace("__ROOT_ID__", root_id).replace(
            "__FILTER_EXPR__", filter_expr.replace('"', '\\"')
        )

        env = self.env
        serial = env.new_serialno("needsvg")
        targetid = f"needsvg-{env.docname}-{serial}"

        if not hasattr(env, "needsvg_all_data"):
            env.needsvg_all_data = {}

        env.needsvg_all_data[targetid] = {
            "docname": env.docname,
            "lineno": self.lineno,
            "content": content,
            "options": {
                "width": width,
                "height": "auto",
                "align": align,
                "debug": False,
            },
        }

        targetnode = nodes.target("", "", ids=[targetid])
        node = Needsvg("")
        node["targetid"] = targetid
        return [targetnode, node]


def setup(app: Sphinx) -> None:
    """Register the needsysml-bdd-svg directive."""
    app.add_directive("needsysml-bdd-svg", NeedsymlBddSvgDirective)

