# Package — nested packages with dependency arrows. Walks the package
# tree under the root, emits PlantUML `package "X" { … }` blocks
# (recursively via Jinja macro). Dependencies render as `..>` with the
# `<<kind>>` stereotype label.
PKG_FULL_TEMPLATE = """\
@startuml
{% set root_id = "{root_id}" %}
{% set max_depth = {depth} %}
{% set all_packages = filter("type == 'Package'") | list %}
{% set deps = filter("type == 'Dependency'") | list %}
{% set rendered = namespace(ids=[]) %}
{% macro render_pkg(pkg_id, depth) %}
{% if depth <= max_depth %}
{% set pkg = needs.get(pkg_id) %}
{% if pkg %}
package "{{ pkg.title }}" as {{ pkg.id }} [[{{ ref(pkg.id) }}]] {
{% set _ = rendered.ids.append(pkg.id) %}
{% for child in all_packages if child.parent_package == pkg.id %}
{{ render_pkg(child.id, depth + 1) }}
{% endfor %}
}
{% endif %}
{% endif %}
{% endmacro %}
{{ render_pkg(root_id, 1) }}
{% for d in deps %}
{% if d.source in rendered.ids and d.target in rendered.ids %}
{{ d.source }} ..> {{ d.target }} : <<{{ d.kind or 'use' }}>>
{% endif %}
{% endfor %}
@enduml
"""


